class Solution:
    def minimumSubstringsInPartition(self, s: str) -> int:
        n = len(s)
        if n == 0:
            return 0

        # Precompute balanced matrix
        balanced = [[False] * n for _ in range(n)]
        for i in range(n):
            freq = {}
            for j in range(i, n):
                c = s[j]
                if c in freq:
                    freq[c] += 1
                else:
                    freq[c] = 1
                counts = list(freq.values())
                if all(x == counts[0] for x in counts):
                    balanced[i][j] = True
                else:
                    balanced[i][j] = False

        # Initialize DP array
        dp = [float('inf')] * (n + 1)
        dp[0] = 0

        for i in range(1, n + 1):
            for j in range(i):
                if balanced[j][i - 1]:
                    dp[i] = min(dp[i], dp[j] + 1)

        return dp[n] if dp[n] != float('inf') else 0

