def max_a(N, b):
    low = 1
    high = N
    while low <= high:
        mid = (low + high) // 2
        power = 1
        overflow = False
        for _ in range(b):
            power *= mid
            if power > N:
                overflow = True
                break
        if overflow:
            high = mid - 1
        else:
            low = mid + 1
    return high

