class Solution:
    def countOfPeaks(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        n = len(nums)

        class FenwickTree:
            def __init__(self, size):
                self.n = size
                self.tree = [0] * (self.n + 1)  # 1-based indexing

            def update(self, idx, delta):
                while idx <= self.n:
                    self.tree[idx] += delta
                    idx += idx & -idx

            def query(self, idx):
                res = 0
                while idx > 0:
                    res += self.tree[idx]
                    idx -= idx & -idx
                return res

            def range_query(self, l, r):
                return self.query(r) - self.query(l - 1)

        ft = FenwickTree(n - 2)

        for i in range(1, n - 1):
            if nums[i] > nums[i - 1] and nums[i] > nums[i + 1]:
                ft.update(i, 1)

        res = []

        for q in queries:
            if q[0] == 1:
                l = q[1]
                r = q[2]
                a = l + 1
                b = r - 1
                if a > b:
                    res.append(0)
                else:
                    if a < 1 or b > (n - 2):
                        res.append(0)
                    else:
                        res.append(ft.range_query(a, b))
            else:
                index = q[1]
                val = q[2]
                original_val = nums[index]
                for i in [index - 1, index, index + 1]:
                    if 1 <= i <= n - 2:
                        # Check old_peak
                        old_peak = 0
                        if nums[i] > nums[i - 1] and nums[i] > nums[i + 1]:
                            old_peak = 1
                        # Update the value
                        nums[index] = val
                        # Check new_peak
                        new_peak = 0
                        if nums[i] > nums[i - 1] and nums[i] > nums[i + 1]:
                            new_peak = 1
                        if old_peak != new_peak:
                            ft.update(i, new_peak - old_peak)

        return res

