import math

class Solution:
    def nonSpecialCount(self, l: int, r: int) -> int:
        # Compute the lower and upper bounds for primes p where p^2 is in [l, r]
        low = math.isqrt(l)
        if low * low < l:
            low += 1
        high = math.isqrt(r)

        if low > high:
            return r - l + 1

        # Generate sieve up to high
        sieve = [True] * (high + 1)
        sieve[0] = sieve[1] = False
        for i in range(2, int(math.isqrt(high)) + 1):
            if sieve[i]:
                sieve[i*i : high+1 : i] = [False] * len(sieve[i*i : high+1 : i])

        # Count primes in [low, high]
        count = 0
        for i in range(low, high + 1):
            if sieve[i]:
                count += 1

        return (r - l + 1) - count

class Solution:
    def numberOfAlternatingGroups(self, colors: List[int], queries: List[List[int]]) -> List[int]:
        n = len(colors)
        # Initialize diff array
        diff = [0] * n
        for i in range(n):
            next_i = (i + 1) % n
            if colors[i] != colors[next_i]:
                diff[i] = 1
            else:
                diff[i] = 0

        # Compute len_start array
        len_start = [0] * n
        current_length = 0
        for i in range(n-1, -1, -1):
            if diff[i] == 1:
                current_length += 1
            else:
                current_length = 0
            len_start[i] = current_length

        res = []

        for query in queries:
            if query[0] == 2:
                # Update query
                index = query[1]
                new_color = query[2]
                if colors[index] == new_color:
                    continue
                colors[index] = new_color
                # Update diff for (index-1) % n and index
                for j in [(index - 1) % n, index]:
                    prev = (j - 1) % n
                    next_i = (j + 1) % n
                    if colors[prev] != colors[j]:
                        diff[j] = 1
                    else:
                        diff[j] = 0
                # Recompute len_start
                current_length = 0
                for i in range(n-1, -1, -1):
                    if diff[i] == 1:
                        current_length += 1
                    else:
                        current_length = 0
                    len_start[i] = current_length
            else:
                k = query[1]
                if k % 2 != 0:
                    res.append(0)
                else:
                    m = k - 1
                    count = 0
                    for i in range(n):
                        if len_start[i] >= m:
                            count += 1
                    res.append(count)

        return res

