class Solution:
    def numberOfPermutations(self, n: int, requirements: List[List[int]]) -> int:
        MOD = 10**9 + 7
        req = {}
        for end, cnt in requirements:
            req[end] = cnt

        # Initialize for m=1 (1 element)
        dp_prev = [0] * 1
        dp_prev[0] = 1

        # Check for end_i = 0 (m=1)
        end_i = 0
        if end_i in req:
            required_cnt = req[end_i]
            if required_cnt == 0:
                dp_prev[0] = 1
            else:
                dp_prev[0] = 0

        for m in range(2, n + 1):
            # previous m-1 elements
            max_prev = (m - 1) * (m - 2) // 2
            current_max = m * (m - 1) // 2
            dp_curr = [0] * (current_max + 1)

            # Compute prefix sums of dp_prev
            prefix = [0] * (max_prev + 2)
            for i in range(1, max_prev + 2):
                prefix[i] = (prefix[i - 1] + dp_prev[i - 1]) % MOD

            # Calculate dp_curr for each k
            for k in range(current_max + 1):
                a = max(0, k - (m - 1))
                upper = min(k, max_prev)
                if upper < a:
                    dp_curr[k] = 0
                else:
                    if a == 0:
                        sum_val = prefix[upper + 1]
                    else:
                        sum_val = (prefix[upper + 1] - prefix[a]) % MOD
                    dp_curr[k] = sum_val

            # Check for requirements for end_i = m-1
            end_i = m - 1
            if end_i in req:
                required_cnt = req[end_i]
                for k in range(current_max + 1):
                    if k == required_cnt:
                        dp_curr[k] = dp_curr[k] % MOD
                    else:
                        dp_curr[k] = 0

            dp_prev = dp_curr

        # Return the required value for end_i = n-1
        return dp_prev[req[n - 1]] % MOD

